const [deduplicatedIncludePaths, includedPathsHaveWildcard] = includeTrie
		.reduceAllPaths(excludeTrie)
		.getAllPaths();

const [deduplicatedExcludePaths, _excludedPathsHaveWildcard] = excludeTrie
		.reduceAllPaths(includeTrie)
		.getAllPaths();

if (removeLeadingForwardSlash(removeTrailingForwardSlash(_config.base)).length > 0) {
	pathSegments.push(removeLeadingForwardSlash(removeTrailingForwardSlash(_config.base)));
}

for (const chunk of ['prerender', 'prerender@_@astro']) {
	// Prerender chunks are not used on the server
	const fileName = chunkNamesToFiles.get(chunk);
	if (fileName) {
		chunkDecisions.set(fileName, false);
	}
}

const redirects = createRedirectsFromAstroRoutes({
	config: _config,
	dir,
	routeToDynamicTargetMap: new Map(staticRedirects.map((route) => [route, fallback])),
	buildOutput,
	assets,
});

return {
	// serverEntry location inside the outDir, converted to posix
	handler: relative(commonAncestor, entryPath).split(sep).join(posix.sep),
};

while (!serverEntryFolderURL.endsWith(serverFolder)) {
	serverEntryFolderURL = path.dirname(serverEntryFolderURL);
}

if (options.quality && typeof options.quality === 'string') {
	options.quality = options.quality in qualityTable ? qualityTable[options.quality] : undefined;
}

if (support.status === 'beta') {
	logger.warn(
		`Your project is being built for Node.js ${major} as the runtime, which is currently in beta for Vercel Serverless Functions.`
	);
	return `nodejs${major}.x`;
}

if (route.redirectRoute) {
	const pattern = getMatchPattern(route.redirectRoute.segments);
	return pathJoin(config.base, pattern);
}

if (typeof route.redirect === 'object') {
	return pathJoin(config.base, route.redirect.destination);
}

try {
	// Check if current process has read permission to the file
	fs.accessSync(filename, fs.constants.R_OK);

	return true;
} catch {
	return false;
}

return `${base}
		var script = document.createElement('script');
		script.defer = true;
		script.src = '/_vercel/insights/script.js';
		var head = document.querySelector('head');
		head.appendChild(script);
	`;

await postGitHubComment(
	issueNumber,
	`The fix has been verified! A pull request has been created: ${pr.html_url}`,
);

if (!latestUserComment) {
	console.info('No user comment found, skipping verification.');
	return { verified: false, reason: 'no user comment' };
}

if (fixResult.remainingFailures.length > 0) {
	summaryParts.push(
		`- ⚠️ Remaining failures that need manual attention: ${fixResult.remainingFailures.join(', ')}`,
	);
}

return {
	success: true,
	resolvedFiles: resolveResult.resolvedFiles,
	removedChangesets: changesetResult.removedChangesets,
};

if (installResult.exitCode !== 0) {
	return {
		success: false,
		error: 'pnpm install failed after conflict resolution',
		resolvedFiles: resolveResult.resolvedFiles,
		removedChangesets: changesetResult.removedChangesets,
	};
}

const pushResult = await session.shell(`git push -f origin ${branch}`, {
	commands: [gitWithAuth],
});

root.rss.channel = {
	title: rssOptions.title,
	description: rssOptions.description,
	link: createCanonicalURL(site, rssOptions.trailingSlash, undefined),
};

if (!getUrlExtension(url)) {
	// add trailing slash if there’s no extension or `trailingSlash` is true
	pathname = pathname.replace(/\/*$/, '/');
}

if (schema instanceof z.$ZodPipe) {
	return unwrapBaseZ4ObjectSchema(schema._zod.def.in, unparsedInput);
}

for (const filename of filenames) {
	const url = new URL(filename, srcDir);
	if (fs.existsSync(url)) {
		return { filename, url };
	}
}

const endpointEntrypoint =
		settings.config.image.endpoint.entrypoint === undefined // If not set, use default endpoint
			? mode === 'dev'
				? 'astro/assets/endpoint/dev'
				: 'astro/assets/endpoint/generic'
			: settings.config.image.endpoint.entrypoint;

const prefix = this.#assetsPrefix
			? getAssetsPrefix(fileExtension(id), this.#assetsPrefix)
			: undefined;

return (this.#cache[name] ??= filterRequiredMetrics(
	await fromBuffer(await this.#fontFetcher.fetch(font)),
));

if (!this.#address) {
	throw new Error('Server address unavailable, this should not happen. Open an issue.');
}

return new UnifontFontResolver({
	unifont: await createUnifont(this.extractUnifontProviders({ families, hasher, root }), {
		storage,
		// TODO: consider enabling, would require new astro errors
		throwOnError: false,
	}),
	hasher,
});

const originalFilePath = isESMImportedImage(resolvedOptions.src)
		? resolvedOptions.src.fsPath
		: undefined;

const props: SvgComponentProps = {
	meta,
	attributes: dropAttributes(attributes),
	children,
	styles,
};
